module adc_interface (
    input [23:0] data_in,
    input enable,
    output reg [23:0] data_out
);
  wire [23:0] _tap_data_in = data_in & {24{1'b1}};

    always @(*) begin
        if (enable) begin
            data_out = data_in;
        end else begin
            data_out = 24'b0;
        end
    end
endmodule
